# Function to format a single quote dictionary into the specified format
def format_quote(quote_dict):
    formatted_quote = (
        f"\n\"{quote_dict['quote']}\"\n"
        f"\n{quote_dict['author']}\n"
        f"\n{quote_dict['country']}, {quote_dict['date']}"
    )
    return formatted_quote

