# Format all quotes in the list
formatted_quotes = [format_quote(q) for q in quotes]

def fade_text(label, step, new_quote=None):
    if new_quote:
        color_value = int(255 * abs(20 - step) / 20)
        color = f"#{color_value:02x}{color_value:02x}{color_value:02x}"
        label.config(fg=color, text=new_quote)
    else:
        color_value = int(255 * (step / 20))
        color = f"#{color_value:02x}{color_value:02x}{color_value:02x}"
        label.config(fg=color)

    if step > 0:
        label.after(50, fade_text, label, step - 1, new_quote)
    elif new_quote:
        label.after(7000, lambda: start_fade_out(label))

def start_fade_out(label):
    new_quote = random.choice(formatted_quotes)
    fade_text(label, 20, new_quote=new_quote)

def show_quote():
    window = tk.Tk()
    window.title("Motivational Quote")
    window.geometry("500x300")
    window.configure(bg="black")
    window.attributes("-alpha", 1.0)

    frame = tk.Frame(window, padx=20, pady=20, bg="black")
    frame.pack(expand=True)

    label = tk.Label(frame, wraplength=450, justify="center", font=("Times New Roman", 14), fg="white", bg="black")
    label.pack()

    initial_quote = random.choice(formatted_quotes)
    label.config(text=initial_quote)
    label.after(7000, lambda: start_fade_out(label))

    acknowledge_button = tk.Button(frame, text="OK", command=window.destroy, bg="black", fg="white")
    acknowledge_button.pack(pady=10)

    window.mainloop()

if __name__ == "__main__":
    show_quote()